/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWPedidoTelevendas-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&PedVenCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Vended.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedVenCod EndIf
If not (&PedSts.IsEmpty() AND &PedNovStsCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Est.") If Not &PedSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PedSts.EnumerationDescription() Endif &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = &PedNovStsCod EndIf
If not (&PedCod.IsEmpty() AND &PedCliCod.IsEmpty() AND &PedStsFin.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Pedido") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Cliente") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = &PedCliCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 4, "Fin.") If Not &PedStsFin.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = &PedStsFin.EnumerationDescription() Endif EndIf
If not (&PedNovStsFinCod.IsEmpty()) &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = &PedNovStsFinCod EndIf
If not (&PedDtaEms.IsEmpty() AND &PedDtaEms_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Emissão") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaEms WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "até") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaEms_To EndIf
If not (&FilCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filial") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilCod EndIf
If not (&PedBlq.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Bloqueado Usuario") If Not &PedBlq.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PedBlq.EnumerationDescription() Endif EndIf
If not (&LctAtuSal.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Atualiza Saldos") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &LctAtuSal.EnumerationDescription() EndIf
If not (&LctTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Lançamento Tipo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &LctTip.EnumerationDescription() EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo Lcto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LctCod1 EndIf Case &DynamicFiltersSelector1 = !'PEDDTAFAT' &PedDtaFat1.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat1.IsEmpty() OR not &PedDtaFat_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Faturado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaFat1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaFat_To1 EndIf Case &DynamicFiltersSelector1 = !'PEDNUM' &PedNum1.FromString(&GridStateDynamicFilter.Value) If not &PedNum1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ped.Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedNum1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo Lcto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LctCod2 EndIf Case &DynamicFiltersSelector2 = !'PEDDTAFAT' &PedDtaFat2.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat2.IsEmpty() OR not &PedDtaFat_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Faturado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaFat2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaFat_To2 EndIf Case &DynamicFiltersSelector2 = !'PEDNUM' &PedNum2.FromString(&GridStateDynamicFilter.Value) If not &PedNum2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ped.Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedNum2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo Lcto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LctCod3 EndIf Case &DynamicFiltersSelector3 = !'PEDDTAFAT' &PedDtaFat3.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat3.IsEmpty() OR not &PedDtaFat_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Faturado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PedDtaFat3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "até" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PedDtaFat_To3 EndIf Case &DynamicFiltersSelector3 = !'PEDNUM' &PedNum3.FromString(&GridStateDynamicFilter.Value) If not &PedNum3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ped.Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PedNum3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&VisibleColumnCount = 0 If &Session.Get(!'WWPedidoTelevendasColumnsSelector') <> '' &ColumnsSelectorXML = &Session.Get(!'WWPedidoTelevendasColumnsSelector') &ColumnsSelector.FromXml(&ColumnsSelectorXML) Else Do 'InitializeColumnsSelector' EndIf
&ColumnsSelector.Columns.Item(4).IsVisible = False &ColumnsSelector.Columns.Item(8).IsVisible = False For &ColumnsSelector_Column in &ColumnsSelector.Columns If &ColumnsSelector_Column.IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = GetMessageText(iif(&ColumnsSelector_Column.DisplayName.IsEmpty(), &ColumnsSelector_Column.ColumnName, &ColumnsSelector_Column.DisplayName)) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Color = 11 &VisibleColumnCount += 1 EndIf EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order EmpCod FilCod (PedDtaPrv) when &OrderedBy = 3 order EmpCod FilCod PedDtaPrv when &OrderedBy = 4 order PedCod when &OrderedBy = 5 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 5 AND &OrderedDsc = True order PedDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (PedDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order PedDtaPrv when &OrderedBy = 7 AND &OrderedDsc = False order (PedDtaPrv) when &OrderedBy = 7 AND &OrderedDsc = True order PedDtaFat when &OrderedBy = 8 AND &OrderedDsc = False order (PedDtaFat) when &OrderedBy = 8 AND &OrderedDsc = True order PedVlrBrt when &OrderedBy = 9 AND &OrderedDsc = False order (PedVlrBrt) when &OrderedBy = 9 AND &OrderedDsc = True order PedVlrLiq when &OrderedBy = 10 AND &OrderedDsc = False order (PedVlrLiq) when &OrderedBy = 10 AND &OrderedDsc = True order LctCod when &OrderedBy = 11 AND &OrderedDsc = False order (LctCod) when &OrderedBy = 11 AND &OrderedDsc = True
using DSWWPedidoTelevendas(&PedVenCod, &PedSts, &PedNovStsCod, &PedCod, &PedCliCod, &PedStsFin , &PedNovStsFinCod, &PedDtaEms, &PedDtaEms_To, &FilCod, &PedBlq, &LctAtuSal , &LctTip, &DynamicFiltersSelector1, &LctCod1, &PedDtaFat1, &PedDtaFat_To1, &PedNum1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &LctCod2, &PedDtaFat2, &PedDtaFat_To2, &PedNum2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &LctCod3, &PedDtaFat3, &PedDtaFat_To3, &PedNum3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &VisibleColumnCount = 0 If &ColumnsSelector.Columns.Item(1).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = PedCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(2).IsVisible = True &gridPedCliCodRaz = iif(PedCliCodRaz.Length() > 30, Substr(PedCliCodRaz,1,30)+'...', PedCliCodRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(&gridPedCliCodRaz) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(3).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = PedDtaEms &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(5).IsVisible = True &NovoStatusFinanceiro = trim(PedNovStsFinNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(&NovoStatusFinanceiro) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(6).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = PedDtaPrv &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(7).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = PedDtaFat &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(9).IsVisible = True &AuxFin = UPPER(Substr(PedStsFin.EnumerationDescription(), 1,3)) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(&AuxFin) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(10).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = PedVlrBrt &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(11).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = PedVlrLiq &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(12).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = LctCod &VisibleColumnCount += 1 EndIf
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"PedCod", '', !'Pedido', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&gridPedCliCodRaz", '', !'Razão/Nome Cliente', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"PedDtaEms", '', !'Emitido', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&NovoStatus", '', !'Status', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&NovoStatusFinanceiro", '', !'Crédito', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"PedDtaPrv", '', !'Previsão', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"PedDtaFat", '', !'Faturado', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&AuxEst", '', !'Est.', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&AuxFin", '', !'Fin.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"PedVlrBrt", '', !'Bruto', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"PedVlrLiq", '', !'Líquido ', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"LctCod", '', !'Lcto', True, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'WWPedidoTelevendasColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWPedidoTelevendasGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWPedidoTelevendasGridState")) Else &GridState.FromXml(&Session.Get(!"WWPedidoTelevendasGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDVENCOD" &PedVenCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSCOD" &PedNovStsCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSFIN" &PedStsFin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSFINCOD" &PedNovStsFinCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

